<template>
  <div class="getProduct">
    <div class="border-bottom d-flex justify-content-between main_header_bg_shadow">
      <h5 class="m-0 ml-4 d-flex" style="padding: 10px 0px">
        Подсчет склада
      </h5>
    </div>
    <div class="container-fluid mt-4">
      <div class="row">
        <div class="col-12">
          <div class="px-0 card p-3">
            <div class="d-flex justify-content-between align-items-center mb-3">
              <div>
                <span class="header_name ml-2">Подсчет склада</span>
                <small v-if="counter_user_name" class="ml-2 text-muted">
                  ({{ $t('sanagan') || 'Sanagan' }}: {{ counter_user_name }})
                </small>
              </div>
              <div class="d-flex">
                <div style="position: relative; margin-top: 1px; width:200px;" class="mr-2"> 
                  <small class="bg-white" style="position: absolute; z-index:1; left:10px; top: -11px; color: #757575;">
                    {{$t('date')}}
                  </small>
                  <mdb-input 
                    type="date"
                    size="sm"
                    class="m-0 p-0" 
                    v-model="Start_time" 
                    outline
                  />
                </div>
                <div style="width:250px">
                  <erpSelectSklad
                    :options="allSklad.rows"
                    @select="selectOptionSklad"
                    :selected="sklad_name"
                    :label="$t('sklad')"
                    size="sm"
                  />
                </div>
              </div>
            </div>

            <div id="sklad_count_table">
              <template v-if="loading">
                <loader-table />
              </template>
              <template v-else>
                <table class="myTableSkladCount">
                  <thead>
                    <tr class="header py-3 table_header_bg">
                      <th width="40" class="text-left">№</th>
                      <th width="300">{{$t('product')}}</th>
                      <th>{{$t('qty')}} (sanash)</th>
                      <!-- <th>{{$t('Farq')}}</th> -->
                      <th>{{$t('measurment')}}</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr 
                      v-for="(row, rowIndex) in productList" 
                      :key="rowIndex"
                      :style="{background: row.product && row.product.shitrix_code ? row.product.shitrix_code : ''}"
                    >
                      <td><span>{{rowIndex + 1}}</span></td>
                      <td><span>{{row.productName}}</span></td>
                      <td>
                        <input 
                          type="text" 
                          :value="row.count_qty_str" 
                          :readonly="!isToday"
                          @keyup="funcCountQty($event.target.value, rowIndex)" 
                          @keydown="handleTabKey($event, rowIndex)"
                          @click="countQtyClickNull(rowIndex)" 
                          @blur="funcAllBlur(rowIndex)"   
                          class="form-control border mt-0 pr-2" 
                          style="border:none; outline:none; height:24px; font-size: 13px; font-weight: bold;" 
                          tabindex="0"
                        />  
                      </td>
                      <!-- <td 
                        :class="{
                          'bg-white': row.diff_qty == 0, 
                          'bg-success': row.diff_qty > 0, 
                          'bg-danger': row.diff_qty < 0
                        }"
                      > 
                        <span>{{ formatDiffQty(row.diff_qty) }}</span>
                      </td> -->
                      <td><span>{{row.unitM && row.unitM.name ? row.unitM.name : ''}}</span></td>
                    </tr>
                  </tbody>
                </table>
              </template>
            </div>

            <div class="d-flex justify-content-end mt-3">
              <mdb-btn 
                v-if="sklad_id && productList.length > 0 && isToday" 
                class="m-0 mb-1"  
                size="sm" 
                outline="success" 
                style="font-size:12px; height:35px; min-width: 120px;" 
                @click="saveDiff"
                :disabled="saving"
              >
                <span v-if="!saving">{{ $t('save') }}</span>
                <span v-else>{{ $t('Saving') }}...</span>
              </mdb-btn>
            </div>
          </div>
        </div>
      </div>
    </div>
    
    <block ref="blocked"></block>
    <massage_box 
      :hide="modal_status" 
      :detail_info="modal_info"
      :m_text="$t('Failed_to_add')" 
      @to_hide_modal="modal_status = false"
    />
    <Toast ref="message"></Toast>
  </div>
</template>

<script>
import { mdbInput, mdbBtn } from "mdbvue"
import { mapActions, mapGetters } from 'vuex'
import LoaderTable from '../../components/loaderTable.vue';
import erpSelectSklad from "../../components/erpSelect.vue";

export default {
  data() {
    return {
      modal_info: '',
      modal_status: false,
      loading: false,
      saving: false,
      search: '',
      sklad_name: '',
      sklad_id: null,
      sklad_list_access: [],
      Start_time: '',
      productList: [],
      adminStatus: localStorage.AccessType,
      counter_user_name: '',
    }
  },
  components: {
    mdbInput,
    mdbBtn,
    LoaderTable,
    erpSelectSklad
  },
  computed: {
    ...mapGetters(['allSklad']),
    isToday() {
      if (!this.Start_time) return false;
      const today = new Date();
      const todayStr = today.toISOString().slice(0, 10);
      return this.Start_time === todayStr;
    }
  },
  async mounted() {
      // Bugungi sanani o'rnatish
      const today = new Date();
      this.Start_time = today.toISOString().slice(0, 10);
      await this.fetchSklad();
      // Foydalanuvchi ruxsatlarini tekshirish
      // await this.fetchUserAccess(localStorage.user_id);
      // await this.fetchUserSkladAccess();

      // Agar skladlar mavjud bo'lsa, birinchisini tanlash
      if (this.allSklad.rows.length > 0) {
        await this.selectOptionSklad(this.allSklad.rows[0]);
      }
    },
  watch: {
    async Start_time(newVal, oldVal) {
      if (!newVal || newVal === oldVal) return;
      if (this.sklad_id) {
        await this.loadSkladProducts(this.sklad_id);
      }
    }
  },
  methods: {
    ...mapActions(['fetchSklad']),

    // async fetchUserAccess(id) {
    //   try {
    //     const res = await fetch(this.$store.state.hostname + '/TegirmonUserAccess/getTegirmonUserAccessUserId?user_id=' + id);
    //     const data = await res.json();
    //     if (res.status == 200 || res.status == 201) {
    //       if (data.num_2 == 0) {
    //         this.$refs.blocked.show_block();
    //       }
    //     }
    //   } catch (error) {
    //     console.log(error)
    //   }
    // },

    async fetchUserSkladAccess() {
      try {
        const res = await fetch(this.$store.state.hostname + '/TegirmonUserSkladAccess/getSkladsByUserId?user_id=' + localStorage.user_id);
        const data = await res.json();
        if (res.status == 200 || res.status == 201) {
          this.sklad_list_access = data;
          if (data.length == 0) {
            this.$refs.blocked.show_block();
          }
        }
      } catch (error) {
        console.log(error)
      }
    },

    async selectOptionSklad(option) {
      this.sklad_name = option.name;
      this.sklad_id = option.id;
      await this.loadSkladProducts(this.sklad_id);
    },

    async loadSkladProducts(skladId) {
      try {
        this.loading = true;
        const response = await fetch(
          this.$store.state.hostname + "/TegirmonSkladHistory/getSkladStatistika?sklad_id=" + skladId
        );
        const data = await response.json();
        console.log('sklad products',data);
        if (response.status == 201 || response.status == 200) {
          // ProductList ni tayyorlash
          this.productList = data.map(x => ({
            productId: x.productId,
            productName: x.productName,
            product: x.product,
            currentQty: x.currentQty,
            unitM: x.unitM,
            count_qty: 0, // Boshlang'ich qiymat 0
            count_qty_str: '0',
            diff_qty: -x.currentQty // Boshlang'ich farq -ostatka
          }));

          // Diff larni yuklash (shu sana va sklad bo'yicha)
          await this.loadDiffForToday(skladId);
        } else {
          this.modal_info = data;
          this.modal_status = true;
        }
      } catch (error) {
        this.modal_info = this.$i18n.t('network_ne_connect');
        this.modal_status = true;
      } finally {
        this.loading = false;
      }
    },

    async loadDiffForToday(skladId) {
      try {
        const res = await fetch(
          this.$store.state.hostname +
          '/TegirmonSkladDiffControler/get-by-date?date=' +
          this.Start_time +
          '&sklad_id=' +
          skladId
        );
        const diffData = await res.json();
        console.log('diff data',diffData);
        if (res.status == 200 || res.status == 201) {
          // Agar diff mavjud bo'lsa, har bir product uchun qty ni o'rnatish
          if (diffData && diffData.length > 0) {
            // Sanagan xodimni topish (auth_user_updator_id)
            const firstWithUser = diffData.find(x => x && x.auth_user_updator_id);
            if (firstWithUser && firstWithUser.auth_user_updator_id) {
              await this.fetchCounterUserName(firstWithUser.auth_user_updator_id);
            } else {
              this.counter_user_name = '';
            }
            const diffMap = {};
            diffData.forEach(diff => {
              diffMap[diff.tegirmonProductId] = diff.qty;
            });

            // ProductList ni yangilash
            this.productList = this.productList.map(product => {
              if (diffMap.hasOwnProperty(product.productId)) {
                const qty = diffMap[product.productId];
                return {
                  ...product,
                  count_qty: qty,
                  count_qty_str: qty.toFixed().toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 '),
                  diff_qty: qty - product.currentQty
                };
              }
              return product;
            });
          }
          else {
            this.counter_user_name = '';
          }
        }
      } catch (error) {
        console.log('Diff yuklashda xatolik:', error);
        // Diff yuklashda xatolik bo'lsa ham, asosiy ro'yxat ko'rsatiladi
      }
    },

    async fetchCounterUserName(userId) {
      try {
        const res = await fetch(this.$store.state.hostname + '/TegirmonUser/' + userId);
        if (res.status == 200 || res.status == 201) {
          const data = await res.json();
          this.counter_user_name = data && data.fio ? data.fio : '';
        } else {
          this.counter_user_name = '';
        }
      } catch (error) {
        this.counter_user_name = '';
      }
    },

    countQtyClickNull(index) {
      if (!this.isToday) return;
      // Agar input qiymati 0 bo'lsa, tozalash
      if (this.productList[index].count_qty_str == '0' || this.productList[index].count_qty == 0) {
        this.productList[index].count_qty_str = '';
        this.productList[index].count_qty = 0;
        const currentQty = this.productList[index].currentQty;
        this.productList[index].diff_qty = -currentQty; // Tozalash bilan farqni yangilash
      }
    },

    funcAllBlur(index) {
      if (!this.isToday) return;
      // Agar input bo'sh bo'lsa, 0 ga qaytarish (ostatka yozilmaydi)
      if (this.productList[index].count_qty_str == '' || this.productList[index].count_qty_str == null) {
        this.productList[index].count_qty = 0;
        this.productList[index].count_qty_str = '0';
      }
      this.productList[index].diff_qty = this.productList[index].count_qty - this.productList[index].currentQty;
    },

    handleTabKey(event, index) {
      if (!this.isToday) return;
      if (event.keyCode === 9 || event.key === 'Tab') {
        let inputValue = this.productList[index].count_qty_str;
        if (inputValue) {
          inputValue = inputValue.replace(/\s/g, '');
        }
        
        // Agar bo'sh yoki 0 bo'lsa, 0 ga qaytarish (ostatka yozilmaydi)
        if (!inputValue || inputValue === '' || inputValue === '0') {
          this.productList[index].count_qty = 0;
          this.productList[index].count_qty_str = '0';
        }
        
        this.funcAllBlur(index);
      }
    },

    funcCountQty(n, index) {
      if (!this.isToday) return;
      var tols = ''
      for (let i = 0; i < n.length; i++) {
        if (n[i] != ' ') {
          tols += n[i];
        }
      }
      if (tols[tols.length - 1] != '0' && tols[tols.length - 1] != '1' && tols[tols.length - 1] != '2' && 
          tols[tols.length - 1] != '3' && tols[tols.length - 1] != '4' && 
          tols[tols.length - 1] != '5' && tols[tols.length - 1] != '6' && 
          tols[tols.length - 1] != '7' && tols[tols.length - 1] != '8' && tols[tols.length - 1] != '9' &&
          tols[tols.length - 1] != '.') {
        tols = tols.slice(0, tols.length - 1)
      }
      this.productList[index].count_qty_str = tols.replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ');
      var temp = ''
      for (let i = 0; i < this.productList[index].count_qty_str.length; i++) {
        if (this.productList[index].count_qty_str[i] != ' ') {
          temp += this.productList[index].count_qty_str[i];
        }
      }
      if (temp == '') {
        this.productList[index].count_qty = 0;
      } else {
        this.productList[index].count_qty = parseFloat(temp) || 0;
      }
      this.productList[index].diff_qty = this.productList[index].count_qty - this.productList[index].currentQty;
    },

    formatNumber(value) {
      if (value === null || value === undefined || isNaN(value)) return 0;
      return Number(value);
    },

    formatDiffQty(value) {
      if (value == null || value == undefined || isNaN(value)) {
        return '0';
      }
      if (value % 1 === 0) {
        return value.toString().replace(/(\d)(?=(\d{3})+(?!\d))/g, '$1 ');
      } else {
        const formatted = parseFloat(value.toFixed(2));
        const parts = formatted.toString().split('.');
        const integerPart = parts[0].replace(/(\d)(?=(\d{3})+(?!\d))/g, '$1 ');
        const decimalPart = parts[1] ? '.' + parts[1] : '';
        return integerPart + decimalPart;
      }
    },

    async saveDiff() {
      if (!this.sklad_id) {
        this.$refs.message.warning('Sklad tanlash kerak');
        return;
      }

      // Barcha mahsulotlarni olamiz (farq 0 bo'lsa ham)
      const diffList = this.productList.map(x => ({
        TegirmonSkladId: this.sklad_id,
        TegirmonProductId: x.productId,
        ostatka: x.currentQty,
        qty: x.count_qty,
        diff: x.diff_qty,
        unit: (x.unitM && x.unitM.name) || '',
        product_name: x.productName,
        product_price: (x.product && x.product.price) || 0,
        user_name: localStorage.user_name || '',
        auth_id: localStorage.AuthId ? parseInt(localStorage.AuthId) : 0,
        auth_user_creator_id: 1, // /sklad_count sahifasidan yozilganligini belgilash uchun
        auth_user_updator_id: localStorage.user_id, // kim sanashni kiritganini bilish uchun
        create_date: this.Start_time + 'T00:00:00'
      }));

      if (diffList.length === 0) {
        this.$refs.message.warning('Mahsulot topilmadi');
        return;
      }

      try {
        this.saving = true;
        
        // Avval eski diff larni o'chirish (shu sana va sklad bo'yicha)
        const deleteResponse = await fetch(
          this.$store.state.hostname + 
          `/TegirmonSkladDiffControler/delete-by-date-and-sklad?date=${this.Start_time}&sklad_id=${this.sklad_id}`,
          {
            method: "DELETE"
          }
        );
        
        const deleteResult = await deleteResponse.json();
        console.log("Eski diff lar o'chirildi:", deleteResult);

        // Keyin yangi diff larni saqlash
        const response = await fetch(
          this.$store.state.hostname + "/TegirmonSkladDiffControler/add-diff-list",
          {
            method: "POST",
            headers: {
              "Content-Type": "application/json"
            },
            body: JSON.stringify(diffList)
          }
        );

        const result = await response.json();

        if (response.ok) {
          console.log("Success:", result);
          this.$refs.message.success('Added_successfully');
          // Ro'yxatni yangilash
          await this.loadSkladProducts(this.sklad_id);
        } else {
          console.error("Error:", result);
          this.$refs.message.warning('Xatolik yuz berdi');
        }
      } catch (error) {
        this.modal_info = error.toString();
        this.modal_status = true;
      } finally {
        this.saving = false;
      }
    },
  },
}
</script>

<style lang="scss" scoped>
::-webkit-scrollbar {
  width: 5px;
}

::-webkit-scrollbar-track {
  background: #fdfdfd;
}

::-webkit-scrollbar-thumb {
  background: #b4c2d6;
}

::-webkit-scrollbar-thumb:hover {
  background: #212d3d;
}

.header_name {
  font-size: 14.5px;
  color: #484d53;
}

.myTableSkladCount {
  table-layout: fixed;
  width: 100%;
  overflow: hidden;
  font-size: 18px;
  max-height: 80px;
  overflow-x: auto;
}

.myTableSkladCount th {
  font-weight: 600;
  font-size: 11px;
}

.myTableSkladCount td {
  font-size: 11px;
}

.myTableSkladCount th,
.myTableSkladCount td {
  text-align: left;
  padding: 5px 10px;
  border: 1px solid rgb(185, 185, 185);
}

.myTableSkladCount th {
  text-align: left;
  padding: 5px 10px;
  border: 1px solid #CBDCE6;
}

.myTableSkladCount tr {
  &:hover {
    background: #afd1fd !important;
  }
}
</style>

